BEGIN;

-- Sanity check: verify current max IDs match expectations before inserting
DO $$
DECLARE
  current_max_q INT;
  current_max_i INT;
BEGIN
  SELECT COALESCE(MAX(question_id), 0) INTO current_max_q FROM bjl_questions_v2;
  SELECT COALESCE(MAX(item_id), 0) INTO current_max_i FROM bjl_items;
  IF current_max_q != 415 THEN
    RAISE EXCEPTION 'Expected max question_id=415, got %', current_max_q;
  END IF;
  IF current_max_i != 5391 THEN
    RAISE EXCEPTION 'Expected max item_id=5391, got %', current_max_i;
  END IF;
END $$;

